const Q_CHEMISTRY_2015=[{"id": "objective>Chemistry>2015>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pollution of water by crude oil can lead to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in carbon (IV) oxide content</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in oxygen content </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in oxygen content </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in growth of aquatic organisms </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pollution of water by crude oil can lead to a decrease in oxygen content. This is because the oil forms a layer on the water surface, preventing the diffusion of oxygen from the atmosphere into the water. This can lead to the death of aquatic organisms that rely on this oxygen.</div>", "topic": "ENVIRONMENTAL POLLUTION : WATER POLLUTION"}, {"id": "objective>Chemistry>2015>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a few drops of Barium Chloride is added to an unknown sample of a substance acidified with Hydrochloric Acid, a white precipitate insoluble in excess of the acid was obtained. The likely anion in the sample is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl- </div>", "<div style=\"font-family:Cambria;font-size:17px;\">S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Co<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is a confirmatory test of some common anions. When a solution is mixed with an aqueous solution of Barium Chloride and then with dilute Hydrochloric acid; the observation is a white precipitate which is insoluble in excess. The conventional inference is the presence of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span>.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2015>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen in air can be removed using </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lime water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">caustic soda solution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyrogallol solution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">slaked lime </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen in air can be removed using pyrogallol solution. Pyrogallol, also known as 1,2,3-trihydroxybenzene, is a chemical compound that readily absorbs oxygen from the air.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2015>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the pH of a solution of 0.0001 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> hydrochloric acid </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The concentration of the acid = 0.0001moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/>  <br/> PH = ?  <br/>  Recall that:  <br/>  PH = - log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">H+</span> ------------- (1) <br/>  Since hydrochloric acid is a monobasic acid, H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> = 1 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>  <br/>  PH = -log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>; PH = -(-4)log<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span> = 4</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2015>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following drying agents is NOT suitable for drying hydrogen sulphide? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CaO </div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> (Sulphuric acid) is not suitable for drying hydrogen sulphide because it reacts with hydrogen sulphide to form sulphur and water. The reaction is as follows: H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> -> 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + 3S. Therefore, it cannot be used as a drying agent for hydrogen sulphide.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2015>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Diamond is used in making jewellery due to its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high refractive index </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transparency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hardness </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high melting point </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diamond is used in the manufacture of jewellery due to its high refractive index.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2015>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of impurities in a solid will make the melting point to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain unchange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">be zero </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of impurities in a solid will make the melting point to decrease. This is because impurities disrupt the regular arrangement of particles in the solid, which weakens the forces holding the particles together and allows the solid to melt at a lower temperature.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : BIOLING AND MELTING POINTS"}, {"id": "objective>Chemistry>2015>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The discovery that protons and neutrons are concentrated at the nucleus of an atom was postulated by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">E. Rutherford </div>", "<div style=\"font-family:Cambria;font-size:17px;\">J. Dalton C. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">J.J. Thomsom </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N. Bohr</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lord Ernest Rutherford gave the explanation that the mass of an atom is concentrated at the nucleus using his Alpha scattering experiment.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2015>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a hygroscopic substance? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NaNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NaNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, sodium trioxonitrate (V) is a hygroscopic substance. These are substances that can absorb moisture from the atmosphere.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2015>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a chemical reaction, when the energy of the colliding reactant particles is less than the activation energy, the reaction will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be spontaneous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">not occur </div>", "<div style=\"font-family:Cambria;font-size:17px;\">occur </div>", "<div style=\"font-family:Cambria;font-size:17px;\">be slow </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a chemical reaction, the activation energy is the minimum energy that the reacting particles must have for a reaction to occur. If the energy of the colliding reactant particles is less than the activation energy, the reaction will not occur.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2015>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The monomer of natural rubber is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2-methylbuta-1,3-diene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1-buten-3-yne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buta-1,3-diene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-chlorobuta-1,3-diene </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Natural polymer is formed from the monomeric unit, isoprene < C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>> or 2-methyl buta -1,3-diene.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2015>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of boron in NaBH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+3 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> +3 <br/> oxidation number of b in nabh4. As the oxidation state of Na is +1 and Hydrogen is -1 because here hydrogen exist as hydride. Hence the oxidation state of boron is +3. <br/>  <br/> Na + B + H4 = 0 <br/> 1 + B+ (-1 x 4 ) = 0 <br/> B = 4 – 1 <br/> B = +3</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2015>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span> ⇒ PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> ∆H = +ve  <br/>  In the above reaction, the forward reaction is favoured by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the size of the containing vessel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding a catalyst</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the temperature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> - The equation:  <br/>  PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> ⇔ PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ∆H = +ve   <br/>  Since the reaction is endothermic, i.e ∆H = +ve, the forward process will be favoured by an increase in temperature.</div>", "topic": "CHEMICAL EQUILIBRIA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2015>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following halogens is the most reactive? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> > Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> > Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> > I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> (Decreasing order of reactivity). <br/>  <br/> fluorine <br/> As a general rule, fluorine is the most reactive halogen and astatine is the least reactive. All halogens form Group 1 salts with similar properties.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2015>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas that forms a black precipitate with lead(II)ethanoate is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When hydrogen sulphide reacts with lead (II) ethanoate, it gives off lead sulphide and ethanoic acid; the black precipitate is lead sulphide. <br/>  <br/>  H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S + (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COO)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Pb → PbS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(Black ppt)</span>+ 2CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>2015>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The common ore of iron is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bauxite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">galena </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cassiterite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetite </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most common ores of iron are haematite, Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, magnetite, Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, iron pyrites, FeS<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, siderite or sphatic iron ore, FeCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and limonite, Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2015>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  A property common to the structures above is that they have the same </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">structural and molecular formulae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structural formula but different molecular formulae </div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of carbon but different molecular mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">molecular formula but different structural formula </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structures above are isomers. Isomers are known to have the same molecular formular but different structure formula.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2015>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of salt that ionize to produce three different ions in solution is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acidic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">complex </div>", "<div style=\"font-family:Cambria;font-size:17px;\">double </div>", "<div style=\"font-family:Cambria;font-size:17px;\">basic </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Double salt is a salt that ionizes to produce three different types of ions in solution, two of these are usually positively charged and the other negatively charged. Double salts are formed by the combination of two simple salts.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2015>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2HBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span>  <br/>  In the reaction above, the oxidizing agent is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S + Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2HBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>   <br/>  * The oxidizing agent is that which is reduced in the reaction  <br/>  * The oxidation number of Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> in the reactant side is O, while at the product side, the oxidation number reduces to -1, hence Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is reduced.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2015>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process whereby a gaseous body loses some of its kinetic energy to a colder body is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">condensation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">melting </div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">freezing </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process described is condensation. Condensation is the phase transition in which a gas or vapour transforms into a liquid due to cooling. During condensation, the kinetic energy of the gas molecules decreases as they release energy in the form  of heat to the colder body (such as a cold surface or cooler surroundings), thereby transitioning into a liquid state. </div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2015>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the quantum numbers determine the energy sub-level in an orbital? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnetic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Principal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Azimuthal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spin </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The azimuthal quantum number, also known as the angular momentum quantum number, determines the energy sub-level or shape of an orbital. It can have any integer value from 0 to n - 1. This quantum number describes the electron's probable location within an energy level, often referred to as an electron cloud.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2015>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fehling's solution can be used to distinguish between </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHO and C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHO and CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH and CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>COOH </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fehling's test or Tollen's test is used particularly to distinguish alkanals from alkanones  <br/>  * Fehling contains copper (II) complex. <br/> </div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>2015>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the molecular formula of a compound with empirical formula CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and vapour density 42?  <br/>  <br/>  <br/> [C = 12, H = 1] <br/> \\</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The empirical formula of the compound = CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, Vapour density = 42  <br/>  Recall: Relative Molecular Mass = 2 x vapour density  <br/>  RMM of the compound = 2 × 42 = 84  <br/>  Recall that  <br/> (RMM Empirical formula)n = RMM Molecular formula  <br/>  (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)n = 84  <br/>  (12 + 2)n = 84  <br/>  14n = 84; n = 6  <br/>  Recall that:  <br/>  (Empirical formula)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> = Molecular formula  <br/>  (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> = Molecular formula = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2015>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The seperation technique that is based on the principle of solubility of a solid in two miscible liquids </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fractional distillation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distilation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">precipitation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Precipitation is the seperation technique that is based on the principle of solubility of a solid in two miscible liquid.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2015>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen bond can be found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen sulphide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen bromide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen fluoride </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen bond is usually formed between hydrogen and the most electronegative element of groups 5, 6 and 7. <br/>  <br/> Hydrogen fluoride, HF contains hydrogen bond; since fluorine is the most electronegative element in group 7 </div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2015>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">24g of magnesium reacts with dilute hydrochloric acid. Calculate the volume of hydrogen gas evolved at s.t.p  <br/> [Mg = 24, Molar volume of gas at s.t.p = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.6dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.2dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">44.8dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of the reaction  <br/> Mg + 2HCl → mgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> From the equation, 24g of magnesium reacts with hydrochloric acid to liberate 1 mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/>  1 mole of any gas at s.t.p = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  ∴ 24g of Mg reacts with HCl to liberate 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> gas.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2015>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium is usually used as electrical cable due to its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">good conductivity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">silver-white appearance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">malleability </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high melting point </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium is used as electrical cable due to its good conductivity. Conductivity refers to the ability of a material to transmit electricity. Aluminium is a good conductor of electricity, which makes it suitable for use in electrical cables.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2015>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A chemical reaction with entropy change of 20 JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and free energy change +55000 J occured at -23<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C. Calculate the enthalpy. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">55,460 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">44,540 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50,000 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60,000 J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The entropy, ∆S = 20JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = 0.02KJK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/> The free energy change, ∆G = + 55000J = +55KJ   <br/> Temperature, T = -23<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = 250K   <br/> Enthalpy, change, ∆H = ?  <br/>  Recall that   <br/>  ∆G = ∆H - T∆S  <br/>  55 = ∆H - 250 x 0.02  <br/>  55 = ∆H - 5  <br/>  ∆H = 60KJ = 60000J </div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2015>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme invertase converts sucrose into </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glucose an glucose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">glucose and galactose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">glucose and fructose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fractose and galactose </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme invertase catalyzes the hydrolysis of sucrose into glucose and fructose. This is a common biochemical reaction in carbohydrate metabolism.</div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>2015>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of lone pair of electron in water molecule is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lone pair of electrons is the pair of electrons that is not taking part in the bonding.  <br/> The structure of water  <br/> We have two lone pairs of electrons in water.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2015>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the illustration below, x and y respectively represent  <br/> n monosaccharide <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> polysaccharide + n/2 water</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydration and fermentation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis and condensation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">condensation and hydrolysis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fermentation and hydration </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the illustration below, x and y respectively represent Condensation and hydrolysis.</div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>2015>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main product of the reaction between phosphorus (V) chloride and ethanol is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chloroethane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloromethane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dichloromethane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dichloroethane </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ethanol reacts vigorously with phosphorous (V) chloride in the cold, it liberates steamy fumes of hydrogen and chloroethane vapour. <br/>  <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH + PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> ⇔ C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + POCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(l)</span> + HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2015>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bond-breaking energies in an endothermic reaction is usually</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equal to the bond-forming energies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">more than the bond-forming energies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than the bond-forming energies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">double the bond-forming energies </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bond-breaking energies in an endothermic reaction is usually more than the bond-forming energies.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2015>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction below, x and y respectively are  <br/>  <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">234</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">90</span>Th → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>Pa + β</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">234 and 91 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">235 and 90 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">233 and 89 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">230 and 86 </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">234</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">90</span>Th → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>Pa + β <br/>  β = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>e  <br/>  <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">234</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">90</span>Th → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>Pa + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>  <br/>  234 = x + 0  <br/>  90 = y - 1; y = 91 <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>Pa = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">234</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">91</span>Pa </div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2015>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The compound of calcium used to make refractory furnace lining is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium trioxonitrate (V) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium hydroxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium chloride </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calcium oxide, is used as a refractory substance (it will not melt even when heated to very high temperature).</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALINE-EARTH METALS"}, {"id": "objective>Chemistry>2015>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of copper deposited when a current of 2.0 A is passed through a solution of copper salt for 60 minutes is.   <br/> [Cu = 64, F = 96500 Cmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.78g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.04g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.39g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.55g </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>   <br/> The current, I = 2.0A  <br/>  The time, t = 60minutes = 60 x 60 = 3600s  Q = It; 2 x 3600 = 7200C  <br/>  Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cu   <br/>  2F deposit 1 mole of copper.  <br/>  1 Farad, 1F = 96500C  <br/>  2F = 2x96500 = 193000C   <br/>  193000C deposits 64 7200C deposits xg   <br/>  1930/72 = 64/x   <br/>  1930x = 72x64   <br/>  x = 72 x 64/1930 = 2.39g</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2015>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds will liberate carbon (IV) oxide on reaction with sodium trioxocarbonate(IV)? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHO </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanoic acid will liberate carbon (IV) oxide because it is an acid. Note that acids react with trioxocarbonate(IV) salts to yield a salt, water and CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2015>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Kerosene is a petroleum fraction that distils over in the temperature range of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">350<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C - 500<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C - 200<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C - 250<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C and above </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kerosene is a petroleum fraction that distils over in the temperature range of 200<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C - 250<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : BIOLING AND MELTING POINTS"}, {"id": "objective>Chemistry>2015>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The preference in the usage of asbestors support to platinum block as a catalyst can be attributed to its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase surface area </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high concentration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low concentration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in surface area </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The preference in the usage of asbestos support to platinum block as a catalyst can be attributed to its increased surface area. A catalyst works by providing a surface for the reaction to take place. The larger the surface area, the more space there is for the reaction to occur, which can increase the rate of the reaction.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2015>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the reduction of ethyl ethanoate with LiAlH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, the product obtained is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanoic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethane </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethyl ethanoate is reduced to ethanol by hydrogen from strong reducing agents like lithium tetrahydridoaluminate (III) to liberate ethanol.  <br/>  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5(l)</span> + 4[H] → 2C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span></div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2015>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sample of a salt was heated on a Bunsen flame. If the colour of the flame turned bluish-green, the metal present is likely to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">potassium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A sample of a salt was heated on a Bunsen flame. If the colour of the flame turned bluish-green, the metal present is likely to be copper. This is because different metals produce different flame colours when heated due to the energy levels of their electrons. Copper ions typically produce a bluish-green flame.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2015>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A salt that loses moisture on exposure to the atmosphere is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">efflorescent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hygroscopic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deliquescent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluorescent </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Efflorescent compounds lose some or all part of their moisture content on exposure to the atmosphere.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2015>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/>  In the graph above, at what temperature is the solubility of KHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and NaCl the same?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">35<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">42<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">37<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">18<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">KHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and NaCl intersect at T = 37<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C. The temperature of KHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and NaCl will be the same at 37<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>.</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2015>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">1050cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of helium gas was produced at -33<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C and 700 mmHg. What volume would the gas occupy at 23<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C and 750mmHg? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,208.7cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">794.59cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">912.16cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1387.50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1050cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>; T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = -33<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = 240k; P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 700mmHg   <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> =Unknown T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> 23<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = 296k ,  P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 750mmHg   <br/>  <br/>  Recall that: <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> ⊣ P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">I</span>T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">I</span>T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/>  <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 700 x 1050 x296  = 750 x 240 <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1,208.7cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>2015>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction below, X is a  <br/>  <br/>  <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>N + X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>H </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">litium atom </div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutron </div>", "<div style=\"font-family:Cambria;font-size:17px;\">helium atom </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deuterium atom </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> + X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+1   <br/>  Let the atomic number of X be a and the mass number be m   <br/>  <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">m</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>H   <br/>  14+m = 17+1   <br/>  7 + a = 8 + 1   <br/>  14 + m = 18; m = 4  <br/>  7 + 9 = 9; a = 2  <br/>  <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>X = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2015>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The colour of phenolphtalein in an alkaline medium is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colourless </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pink </div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Phenolphthalein is a pH indicator that is colorless in acidic solutions and pink in basic or alkaline solutions.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2015>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the molecular formula of a compound with empirical formular CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O and relative molecular mass 120.  <br/> [C = 12, O = 16, H = 1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The empirical formula = CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O  <br/>  The molar mass = 120  <br/>  recall that: <br/> (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> = Molecular formula   <br/>  R.A.M (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> = R.AM  <br/> (12 + 2 + 16)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> = 120   <br/>  30n = 120  <br/>  n = 4  <br/>  Equation (1) because  <br/> (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>.</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2015>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> + 4HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → MnCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(i)</span> <br/>  <br/>  <br/> In the reaction above, MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> acts as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a catalyst agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a bleaching agent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reduction agent </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/>  MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 4HCl → MnCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>  <br/>  MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> acts as an oxidizing agent.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2015>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the mass magnesium that would be deposited by 8 faradays of electricity?   <br/>  [Mg = 24] </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">96g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">72g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">120g </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> 8 Faradays of electricity   <br/>  Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Mg : e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>∝F  <br/>  2 Farads of electricity produces 24g of magnesium  8 Farads of electricity produces 24g of magnesium .  <br/>  2/8 = 24/x   <br/>  2x = 196  <br/>  x = 96g.</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2015>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of he following hydrocarbon will not undergo polymerization reaction? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkene and alkyne do undergo polymerization reaction  <br/>  - Alkanes do not undergo polymerization  <br/>  - C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span> is an alkane  <br/>  - The remaining options belong to either alkane or alkyne.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}];
